<?php
declare(strict_types=1);
require_once __DIR__ . '/includes/site-settings.php';
require_once __DIR__ . '/includes/consultation.php';
$pdo = db(); $settings = consultationSettings($pdo); $errors = [];
$csrfToken = consultationCsrf();
$form = ['full_name'=>'','mobile_number'=>'','email'=>'','project_type'=>'','consultation_type'=>'','consultation_date'=>'','time_slot'=>'','project_location'=>'','project_size'=>'','budget_range'=>'','project_details'=>''];
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    foreach ($form as $key => $default) $form[$key] = trim((string) ($_POST[$key] ?? ''));
    if (!consultationCsrfValid($_POST['csrf_token'] ?? null)) $errors[] = 'Your session expired. Please submit the form again.';
    if (mb_strlen($form['full_name']) < 2 || mb_strlen($form['full_name']) > 180) $errors[] = 'Enter your full name.';
    if (!preg_match('/^[0-9+() .-]{7,40}$/', $form['mobile_number'])) $errors[] = 'Enter a valid mobile number.';
    if ($form['email'] !== '' && !filter_var($form['email'], FILTER_VALIDATE_EMAIL)) $errors[] = 'Enter a valid email address.';
    if (!in_array($form['project_type'], CONSULTATION_PROJECT_TYPES, true)) $errors[] = 'Choose a project type.';
    if (!in_array($form['consultation_type'], CONSULTATION_TYPES, true)) $errors[] = 'Choose a consultation type.';
    if (!consultationDateIsAvailable($form['consultation_date'], $settings)) $errors[] = 'Choose an available future business day.';
    if (!in_array($form['time_slot'], CONSULTATION_SLOTS, true)) $errors[] = 'Choose a valid time slot.';
    if (!$errors && in_array($form['time_slot'], consultationBookedSlots($pdo, $form['consultation_date']), true)) $errors[] = 'That time slot was just booked. Please choose another.';
    if (!isset($_POST['terms'])) $errors[] = 'Please accept the Terms and Privacy notice.';
    $files = $_FILES['reference_images'] ?? null;
    if ($files && is_array($files['name'])) foreach ($files['name'] as $i => $name) if (($files['error'][$i] ?? UPLOAD_ERR_NO_FILE) !== UPLOAD_ERR_NO_FILE) { if (($files['error'][$i] ?? 1) !== UPLOAD_ERR_OK || ($files['size'][$i] ?? 0) > 5 * 1024 * 1024) $errors[] = 'Each reference image must be under 5 MB.'; }
    if (!$errors) try {
        $pdo->beginTransaction(); $reference = consultationReference($pdo, $form['consultation_date']);
        $q = $pdo->prepare('INSERT INTO consultation_bookings (reference_number,full_name,mobile_number,email,project_type,consultation_type,consultation_date,time_slot,project_location,project_size,budget_range,project_details,terms_accepted) VALUES (:reference_number,:full_name,:mobile_number,:email,:project_type,:consultation_type,:consultation_date,:time_slot,:project_location,:project_size,:budget_range,:project_details,1)');
        $q->execute([':reference_number'=>$reference,':full_name'=>$form['full_name'],':mobile_number'=>$form['mobile_number'],':email'=>$form['email'],':project_type'=>$form['project_type'],':consultation_type'=>$form['consultation_type'],':consultation_date'=>$form['consultation_date'],':time_slot'=>$form['time_slot'],':project_location'=>mb_substr($form['project_location'],0,300),':project_size'=>mb_substr($form['project_size'],0,80),':budget_range'=>mb_substr($form['budget_range'],0,120),':project_details'=>mb_substr($form['project_details'],0,5000)]);
        $bookingId = (int) $pdo->lastInsertId(); $uploadDir = __DIR__ . '/uploads/consultations'; if (!is_dir($uploadDir)) mkdir($uploadDir, 0750, true);
        if ($files && is_array($files['name'])) foreach ($files['name'] as $i => $name) if (($files['error'][$i] ?? UPLOAD_ERR_NO_FILE) === UPLOAD_ERR_OK) { $tmp=$files['tmp_name'][$i]; $mime=(new finfo(FILEINFO_MIME_TYPE))->file($tmp); $ext=['image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp'][$mime] ?? ''; if ($ext === '') throw new RuntimeException('Only JPG, PNG, and WebP reference images are allowed.'); $stored=bin2hex(random_bytes(20)).'.'.$ext; if (!move_uploaded_file($tmp,$uploadDir.'/'.$stored)) throw new RuntimeException('An image could not be securely stored.'); $pdo->prepare('INSERT INTO consultation_attachments (booking_id,stored_name,original_name,mime_type,file_size) VALUES (?,?,?,?,?)')->execute([$bookingId,$stored,basename((string)$name),$mime,(int)$files['size'][$i]]); }
        $pdo->commit(); $bookingQuery=$pdo->prepare('SELECT b.*, (SELECT COUNT(*) FROM consultation_attachments a WHERE a.booking_id=b.id) AS attachment_count FROM consultation_bookings b WHERE b.id=?'); $bookingQuery->execute([$bookingId]); $submittedBooking=$bookingQuery->fetch() ?: array_merge($form,['reference_number'=>$reference]); consultationNotify($submittedBooking,$settings,'created'); header('Location: /consultation-booking.php?confirmed='.rawurlencode($reference)); exit;
    } catch (Throwable $e) { if ($pdo->inTransaction()) $pdo->rollBack(); if ($e instanceof PDOException && str_contains($e->getMessage(), 'UNIQUE')) $errors[]='That time slot is no longer available. Please select another.'; else { error_log($e->getMessage()); $errors[]='We could not save your request. Please try again.'; } }
}
$confirmed = preg_match('/^CONS-\d{8}-\d{4}$/', (string) ($_GET['confirmed'] ?? '')) ? $_GET['confirmed'] : '';
$confirmedBooking = null;
if ($confirmed !== '') { $confirmedQuery=$pdo->prepare('SELECT * FROM consultation_bookings WHERE reference_number=?'); $confirmedQuery->execute([$confirmed]); $confirmedBooking=$confirmedQuery->fetch() ?: null; }
$whatsAppUrl = $confirmedBooking ? consultationWhatsAppUrl($confirmedBooking, $settings) : '';
$headerSettings=getHeaderSettings();
?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Book a Consultation | Design24 Studio</title><link rel="stylesheet" href="assets/css/style.css"><style>.booking{max-width:980px;margin:55px auto;padding:0 20px 70px}.booking-card{background:#fff;border-radius:12px;padding:clamp(24px,5vw,50px);box-shadow:0 15px 45px #063d2e18}.booking h1{color:#07553e;margin-top:0}.booking-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px}.booking label{display:block;font-weight:700;margin-bottom:7px}.booking input,.booking select,.booking textarea{width:100%;padding:12px;border:1px solid #b7c4bf;border-radius:5px;font:inherit}.booking textarea{min-height:120px}.booking .wide{grid-column:1/-1}.booking button{margin-top:25px;background:#07553e;color:#fff;border:0;border-radius:5px;padding:14px 26px;font-weight:700;cursor:pointer}.booking .error{background:#fff0f0;color:#8b1e1e;padding:14px;border-radius:5px}.booking .success{background:#eaf8f1;color:#07553e;padding:25px;border-radius:8px}.slot-note{font-size:.9rem;color:#59665f}.terms{display:flex;gap:9px;align-items:flex-start}.terms input{width:auto;margin-top:5px}@media(max-width:650px){.booking-grid{grid-template-columns:1fr}.booking .wide{grid-column:auto}}</style></head><body class="<?= settingEnabled($headerSettings,'show_top_bar')?'has-top-bar':'no-top-bar' ?>"><?php require __DIR__.'/includes/site-header.php'; ?><main class="booking"><section class="booking-card"><?php if($confirmed): ?><div class="success"><h1>Consultation request received</h1><p>Thank you. Your booking reference is <strong><?=siteEscape($confirmed)?></strong>. Our team will contact you shortly to confirm your appointment.</p><a href="index.php">Return to home</a></div><?php else: ?><h1>Book a Consultation</h1><p>Tell us about your space and select a convenient time. Fields marked * are required.</p><?php if($errors): ?><div class="error"><ul><?php foreach($errors as $error): ?><li><?=siteEscape($error)?></li><?php endforeach ?></ul></div><?php endif ?><form method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=siteEscape(consultationCsrf())?>"><div class="booking-grid"><?php foreach(['full_name'=>'Full Name *','mobile_number'=>'Mobile Number *','email'=>'Email Address','project_location'=>'Project Location','project_size'=>'Approximate Project Size (Sq. Ft.)','budget_range'=>'Estimated Budget Range'] as $key=>$label): ?><div><label for="<?=$key?>"><?= $label ?></label><input id="<?=$key?>" name="<?=$key?>" value="<?=siteEscape($form[$key])?>" <?=in_array($key,['full_name','mobile_number'],true)?'required':''?>></div><?php endforeach ?><div><label for="project_type">Project Type *</label><select id="project_type" name="project_type" required><option value="">Choose one</option><?php foreach(CONSULTATION_PROJECT_TYPES as $v):?><option <?=$form['project_type']===$v?'selected':''?>><?=siteEscape($v)?></option><?php endforeach?></select></div><div><label for="consultation_type">Preferred Consultation Type *</label><select id="consultation_type" name="consultation_type" required><option value="">Choose one</option><?php foreach(CONSULTATION_TYPES as $v):?><option <?=$form['consultation_type']===$v?'selected':''?>><?=siteEscape($v)?></option><?php endforeach?></select></div><div><label for="consultation_date">Preferred Date *</label><input id="consultation_date" name="consultation_date" type="date" min="<?=date('Y-m-d')?>" value="<?=siteEscape($form['consultation_date'])?>" required><span class="slot-note">Sunday is closed. Unavailable dates will be checked when submitted.</span></div><div><label for="time_slot">Preferred Time Slot *</label><select id="time_slot" name="time_slot" required><option value="">Choose a time</option><?php foreach(CONSULTATION_SLOTS as $v):?><option <?=$form['time_slot']===$v?'selected':''?>><?=$v?></option><?php endforeach?></select><span class="slot-note">Booked slots cannot be submitted.</span></div><div class="wide"><label for="project_details">Project Details / Requirements</label><textarea id="project_details" name="project_details" maxlength="5000"><?=siteEscape($form['project_details'])?></textarea></div><div class="wide"><label for="reference_images">Upload Reference Images</label><input id="reference_images" name="reference_images[]" type="file" multiple accept="image/jpeg,image/png,image/webp"><span class="slot-note">JPG, PNG, or WebP; maximum 5 MB per file.</span></div><div class="wide terms"><input id="terms" name="terms" type="checkbox" value="1" required><label for="terms">I accept the Terms &amp; Privacy notice and consent to Design24 Studio contacting me about this consultation. *</label></div></div><button type="submit">Submit Consultation Request</button></form><?php endif ?></section></main><?php require __DIR__.'/includes/site-footer.php'; ?><script src="assets/js/script.js"></script></body></html>
